def is_sub_list(sub: list, main: list) -> bool:
    """Return True if 'sub' occurs contiguously within 'main', else False."""
    # Edge cases
    if len(sub) == 0:
        return True          # empty list is considered a sublist of any list
    if len(main) < len(sub):
        return False

    for i in range(len(main) - len(sub) + 1):
        if main[i:i+len(sub)] == sub:
            return True
    return False


